// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const seen = new Set();

return $input.all().filter(item => {

  const key =
    item.json.Employee_ID;

  if (seen.has(key)) {
    return false;
  }

  seen.add(key);

  return true;
});

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const cleaned = [];

for (const item of $input.all()) {

  // Employee ID
  item.json.Employee_ID = item.json.Employee_ID || 0;

 function cleanName(name) {

  if (!name) return "";

  return name
    .toString()
    .trim()

    // Common substitutions
    .replace(/@/g, "a")
    .replace(/3/g, "e")

    // Remove remaining special characters
    .replace(/[^a-zA-Z\s]/g, "")

    // Proper Case
    .toLowerCase()
    .replace(/\b\w/g, char => char.toUpperCase());
}

// First Name
item.json.First_Name = cleanName(item.json.First_Name);

// Last Name
item.json.Last_Name = cleanName(item.json.Last_Name);

// Full Name
const fullName =
  `${item.json.First_Name} ${item.json.Last_Name}`
  .trim()
  .replace(/\s+/g, " ");

item.json.Full_Name =
  fullName || "Unknown";

    // Remove original columns
  delete item.json.First_Name;
  delete item.json.Last_Name;

item.json.Address = item.json.Address
  ? (() => {
      let address = item.json.Address.toString().trim();

      // Keep first 4 characters unchanged
      let prefix = address.substring(0, 4);

      // Apply replacements from 5th character onwards
      let suffix = address.substring(4)
        .replace(/@/g, "a")
        .replace(/3/g, "e")
        .replace(/[^a-zA-Z0-9\s]/g, "");

      return (prefix + suffix)
        .toLowerCase()
        .replace(/\b\w/g, char => char.toUpperCase());
    })()
  : "Unknown";

const validDepartments = [
  "marketing",
  "Finance",
  "IT",
  "Admin",
  "Sales",
  "HR",
];

let dept = item.json.Department
  ? item.json.Department.toString().trim()
  : "";

if (!dept) {
  item.json.Department = "Unknown";
} else {

  // Normalize input for comparison
  const normalizedDept = dept
    .toLowerCase()
    .replace(/[^a-z]/g, "");

  let matchedDepartment = "Unknown";

  for (const validDept of validDepartments) {

    const normalizedValidDept = validDept
      .toLowerCase()
      .replace(/[^a-z]/g, "");

    if (normalizedDept === normalizedValidDept) {
      matchedDepartment = validDept;
      break;
    }
  }

  item.json.Department = matchedDepartment;
}


item.json.Position = item.json.Position
  ? item.json.Position
      .toString()
      .trim()

      // Common replacements
      .replace(/@/g, "a")
      .replace(/3/g, "e")

      // Remove remaining special characters
      .replace(/[^a-zA-Z\s]/g, "")

      // Convert to Proper Case
      .toLowerCase()
      .replace(/\b\w/g, char => char.toUpperCase())

  : "Unknown";

  // email id

function cleanEmail(email) {
  if (!email) return "unknown";
  email = email.toString().trim().toLowerCase();
  const lastAt = email.lastIndexOf("@");
  if (lastAt === -1) {
    return "unknown";
  }

  let localPart = email.substring(0, lastAt);
  let domainPart = email.substring(lastAt + 1);

  localPart = localPart
    .replace(/@/g, "a")
    .replace(/3/g, "e");

  domainPart = domainPart
    .replace(/@/g, "a")
    .replace(/3/g, "e");

  return `${localPart}@${domainPart}`;
}

item.json.Email_ID = cleanEmail(item.json.Email_ID);

  // Phone Number
  item.json.Phone_No = item.json.Phone_No
    ? item.json.Phone_No.toString().trim()
    : "Not Assigned";

  // Numeric Fields
  item.json.Age = item.json.Age || 0;
 item.json.Salary = item.json.Salary
  ? `₹${Number(item.json.Salary).toLocaleString('en-IN')}`
  : "₹0";
  item.json.Work_Hours_Per_Day = item.json.Work_Hours_Per_Day || 0;

// Convert Excel serial date to DD-MM-YYYY

if (item.json.Joining_Date) {

  const excelDate = Number(item.json.Joining_Date);

  const jsDate = new Date(
    (excelDate - 25569) * 86400 * 1000
  );

  const day = String(jsDate.getUTCDate()).padStart(2, '0');
  const month = String(jsDate.getUTCMonth() + 1).padStart(2, '0');
  const year = jsDate.getUTCFullYear();

  item.json.Joining_Date = `${day}-${month}-${year}`;

} else {

  item.json.Joining_Date = "01-01-1900";

}

cleaned.push({
  json: {
    Employee_ID: item.json.Employee_ID,
    Full_Name: item.json.Full_Name,
    Phone_No: item.json.Phone_No,
    Email_ID: item.json.Email_ID,
    Address: item.json.Address,
    Department: item.json.Department,
    Position: item.json.Position,
    Age: item.json.Age,
    Salary: item.json.Salary,
    Joining_Date: item.json.Joining_Date,
    Work_Hours_Per_Day: item.json.Work_Hours_Per_Day
  }
});
}

return cleaned;
